{
  "compilerOptions": {
    "experimentalDecorators": true
  }
}

function LogCreation(target: Function) {
  const original = target;

  function construct(constructor: any, args: any[]) {
    console.log(`Creating instance of: ${constructor.name}`);
    return new constructor(...args);
  }

  const f: any = function(...args: any[]) {
    return construct(original, args);
  };

  f.prototype = original.prototype;
  return f;
}

@LogCreation
class Person {
  constructor(public name: string) {}
}

const p = new Person('Alice');
// Console output: Creating instance of: Person

function LogExecutionTime(
  target: any,
  propertyKey: string,
  descriptor: PropertyDescriptor
) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.time(propertyKey);
    const result = originalMethod.apply(this, args);
    console.timeEnd(propertyKey);
    return result;
  };
  return descriptor;
}

class MathOps {
  @LogExecutionTime
  factorial(n: number): number {
    if (n <= 1) return 1;
    return n * this.factorial(n - 1);
  }
}

const math = new MathOps();
math.factorial(5);
// Console output will show timed logs for factorial method

function NonEmpty(target: any, propertyKey: string) {
  let value = target[propertyKey];

  const getter = () => value;
  const setter = (newVal: string) => {
    if (!newVal || newVal.trim().length === 0) {
      throw new Error(`${propertyKey} cannot be empty.`);
    }
    value = newVal;
  };

  Object.defineProperty(target, propertyKey, {
    get: getter,
    set: setter,
    enumerable: true,
    configurable: true
  });
}

class User {
  @NonEmpty
  name: string = '';

  constructor(name: string) {
    this.name = name;
  }
}

const user = new User('Bob');
// user.name = '';  // Throws error: name cannot be empty.

function LogParameter(target: any, propertyKey: string, parameterIndex: number) {
  console.log(
    `Parameter at position ${parameterIndex} in method ${propertyKey} has been decorated.`
  );
}

class Greeter {
  greet(@LogParameter message: string): void {
    console.log(message);
  }
}

const greeter = new Greeter();
greeter.greet('Hello!');
// Console output: Parameter at position 0 in method greet has been decorated.

function Authenticated(
  target: any,
  propertyKey: string,
  descriptor: PropertyDescriptor
) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    if (!this.isAuthenticated) {
      throw new Error('User is not authenticated.');
    }
    return originalMethod.apply(this, args);
  };
  return descriptor;
}

class Service {
  isAuthenticated = false;

  @Authenticated
  fetchData() {
    return 'Sensitive data';
  }
}

const service = new Service();
// service.fetchData(); // Throws error: User is not authenticated.
service.isAuthenticated = true;
console.log(service.fetchData()); // Outputs: Sensitive data

